import axios from 'axios';

const env = import.meta.env as Record<string, string | undefined>;
const API_BASE = env.VITE_API_URL || 'http://localhost:8000';

export interface GuestLoginRequest {
  device_fingerprint: string;
  user_agent: string;
}

export interface GuestLoginResponse {
  success: boolean;
  user_id: string;
  username: string;
  status: number;
  signed_device_id: string;
  expired_at?: string;
  message?: string;
}

export interface UpgradeRequest {
  phone: string;
  code: string;
  new_username?: string;
}

export interface UpgradeResponse {
  success: boolean;
  user_id?: string;
  username?: string;
  phone?: string;
  status?: number;
  message?: string;
}

export interface RefreshRequest {
  signed_device_id: string;
}

export interface RefreshResponse {
  success: boolean;
  signed_device_id?: string;
  message?: string;
}

export interface UpdateUsernameRequest {
  new_username: string;
}

export interface UpdateUsernameResponse {
  success: boolean;
  username?: string;
  message?: string;
}

class AuthAPI {
  private static instance: AuthAPI;

  private constructor() {}

  public static getInstance(): AuthAPI {
    if (!AuthAPI.instance) {
      AuthAPI.instance = new AuthAPI();
    }
    return AuthAPI.instance;
  }

  async guestLogin(request: GuestLoginRequest): Promise<GuestLoginResponse> {
    const response = await axios.post(
      `${API_BASE}/api/auth/guest-login`,
      request
    );
    return response.data;
  }

  async upgrade(request: UpgradeRequest): Promise<UpgradeResponse> {
    const response = await axios.post(
      `${API_BASE}/api/auth/upgrade`,
      request
    );
    return response.data;
  }

  async refresh(request: RefreshRequest): Promise<RefreshResponse> {
    const response = await axios.post(
      `${API_BASE}/api/auth/refresh`,
      request
    );
    return response.data;
  }

  async updateUsername(request: UpdateUsernameRequest): Promise<UpdateUsernameResponse> {
    const response = await axios.put(
      `${API_BASE}/api/auth/username`,
      request
    );
    return response.data;
  }

  async sendSms(phone: string, scene: string = 'upgrade'): Promise<{ success: boolean; message: string }> {
    const response = await axios.post(
      `${API_BASE}/api/auth/send-sms?phone=${phone}&scene=${scene}`
    );
    return response.data;
  }
}

export const authAPI = AuthAPI.getInstance();

import axios from 'axios';
import type { ChatMessage, ChatResponse, ApiResponse } from '@/types';

const BASE_URL = 'http://localhost:8000/api';

const api = axios.create({
  baseURL: BASE_URL,
  timeout: 120000,
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('access_token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

export const sendChatMessage = async (content: string, paperId?: string): Promise<ApiResponse<ChatResponse>> => {
  const response = await api.post('/chat/message', {
    content,
    paper_id: paperId || null,
  });
  return response.data;
};

export const sendStreamChatMessage = async (
  content: string, 
  paperId?: string,
  onChunk: (chunk: string) => void
): Promise<string> => {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };
  
  const token = localStorage.getItem('access_token');
  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }
  
  const response = await fetch(`${BASE_URL}/chat/stream`, {
    method: 'POST',
    headers,
    body: JSON.stringify({
      content,
      paper_id: paperId || null,
    }),
  });
  
  if (!response.ok) {
    throw new Error(`Request failed with status ${response.status}`);
  }
  
  if (!response.body) {
    throw new Error('Response body is null');
  }
  
  const reader = response.body.getReader();
  const decoder = new TextDecoder('utf-8');
  let fullContent = '';
  let buffer = '';
  
  while (true) {
    const { done, value } = await reader.read();
    
    if (value) {
      buffer += decoder.decode(value, { stream: true });
      
      const lines = buffer.split('\n\n');
      const incomplete = lines.pop() || '';
      buffer = incomplete;
      
      for (const line of lines) {
        if (!line.trim()) continue;
        
        if (line.startsWith('data:')) {
          const chunk = line.slice(5).trimStart();
          fullContent += chunk;
          onChunk(chunk);
        }
      }
    }
    
    if (done) {
      if (buffer.trim()) {
        if (buffer.startsWith('data:')) {
          const chunk = buffer.slice(5);
          fullContent += chunk;
          onChunk(chunk);
        }
      }
      break;
    }
  }
  
  return fullContent;
};

export const getChatHistory = async (paperId?: string, limit: number = 20, offset: number = 0): Promise<ApiResponse<ChatMessage[]>> => {
  const params = new URLSearchParams({
    limit: limit.toString(),
    offset: offset.toString(),
  });
  if (paperId) {
    params.set('paper_id', paperId);
  }
  
  const response = await api.get(`/chat/history?${params.toString()}`);
  return response.data;
};

export const clearChatHistory = async (): Promise<ApiResponse<void>> => {
  const response = await api.delete('/chat/history');
  return response.data;
};

