import { useEffect, useRef, useCallback } from 'react';
import { Spin } from 'antd';
import type { Question } from '@/types';
import { drawHandwriting } from '@/utils/handwriting';

interface AnswerPreviewProps {
  imageUrl: string;
  questions: Question[];
  isLoading?: boolean;
}

export default function AnswerPreview({ imageUrl, questions, isLoading }: AnswerPreviewProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const renderPreview = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas || !imageUrl) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const img = new Image();
    img.crossOrigin = 'anonymous';

    img.onload = () => {
      canvas.width = img.width;
      canvas.height = img.height;

      ctx.drawImage(img, 0, 0);

      questions.forEach((question) => {
        const answer = question.user_answer || question.ai_answer || '';
        if (!answer) return;

        const x = question.answer_x || question.x;
        const y = question.answer_y || (question.y + question.height + 10);
        const width = question.answer_width || question.width;
        const height = question.answer_height || 100;

        drawHandwriting(ctx, answer, x, y, width, height, {
          fontSize: question.font_size,
          color: question.font_color,
        });
      });
    };

    img.src = imageUrl;
  }, [imageUrl, questions]);

  useEffect(() => {
    renderPreview();
  }, [renderPreview]);

  return (
    <div ref={containerRef} style={{ position: 'relative' }}>
      <Spin spinning={isLoading}>
        <canvas
          ref={canvasRef}
          style={{
            maxWidth: '100%',
            height: 'auto',
            border: '1px solid #e8e8e8',
            borderRadius: 4,
          }}
        />
        {!imageUrl && (
          <div style={{
            padding: 60,
            textAlign: 'center',
            color: '#999',
            border: '1px dashed #e8e8e8',
            borderRadius: 4,
          }}>
            请先上传试卷图片
          </div>
        )}
      </Spin>
    </div>
  );
}

import { createContext, useContext, useReducer, useEffect, ReactNode } from 'react';
import { authAPI, GuestLoginResponse } from '../api/auth';
import { generateDeviceFingerprint, DeviceStorage, saveUserState, getUserState, clearUserState } from '../utils/device';

export interface User {
  user_id: string;
  username: string;
  status: number;
  signed_device_id: string;
  expired_at?: string;
}

export interface AuthState {
  user: User | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  error: string | null;
}

type AuthAction =
  | { type: 'LOGIN_START' }
  | { type: 'LOGIN_SUCCESS'; payload: GuestLoginResponse }
  | { type: 'LOGIN_FAILURE'; payload: string }
  | { type: 'LOGOUT' }
  | { type: 'UPGRADE_SUCCESS'; payload: { username: string; status: number } }
  | { type: 'UPDATE_USERNAME'; payload: string };

function authReducer(state: AuthState, action: AuthAction): AuthState {
  switch (action.type) {
    case 'LOGIN_START':
      return { ...state, isLoading: true, error: null };
    case 'LOGIN_SUCCESS':
      const user: User = {
        user_id: action.payload.user_id,
        username: action.payload.username,
        status: action.payload.status,
        signed_device_id: action.payload.signed_device_id,
        expired_at: action.payload.expired_at
      };
      return {
        ...state,
        user,
        isLoading: false,
        isAuthenticated: true,
        error: null
      };
    case 'LOGIN_FAILURE':
      return {
        ...state,
        user: null,
        isLoading: false,
        isAuthenticated: false,
        error: action.payload
      };
    case 'LOGOUT':
      return {
        ...state,
        user: null,
        isLoading: false,
        isAuthenticated: false,
        error: null
      };
    case 'UPGRADE_SUCCESS':
      return state.user
        ? {
            ...state,
            user: {
              ...state.user,
              username: action.payload.username,
              status: action.payload.status
            }
          }
        : state;
    case 'UPDATE_USERNAME':
      return state.user
        ? {
            ...state,
            user: { ...state.user, username: action.payload }
          }
        : state;
    default:
      return state;
  }
}

interface AuthContextType extends AuthState {
  login:
  upgrade: (phone: string, code: string, newUsername?: string) => Promise<boolean>;
  updateUsername: (newUsername: string) => Promise<boolean>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [state, dispatch] = useReducer(authReducer, {
    user: null,
    isLoading: true,
    isAuthenticated: false,
    error: null
  });

  useEffect(() => {
    const initAuth = async () => {
      // 检查是否有本地存储的用户状态
      const savedState = getUserState();
      if (savedState) {
        dispatch({
          type: 'LOGIN_SUCCESS',
          payload: { ...savedState, success: true } as GuestLoginResponse
        });
        return;
      }

      // 尝试自动登录
      await handleAutoLogin();
    };

    initAuth();
  }, []);

  const handleAutoLogin = async () => {
    try {
      dispatch({ type: 'LOGIN_START' });

      const deviceFingerprint = generateDeviceFingerprint();

      const response = await authAPI.guestLogin({
        device_fingerprint: deviceFingerprint,
        user_agent: navigator.userAgent
      });

      if (response.success) {
        dispatch({ type: 'LOGIN_SUCCESS', payload: response });

        // 保存到本地存储
        DeviceStorage.saveDeviceId(response.signed_device_id);
        saveUserState({
          user_id: response.user_id,
          username: response.username,
          status: response.status,
          signed_device_id: response.signed_device_id,
          expired_at: response.expired_at
        });
      } else {
        dispatch({ type: 'LOGIN_FAILURE', payload: response.message || '登录失败' });
      }
    } catch (error) {
      dispatch({
        type: 'LOGIN_FAILURE',
        payload: error instanceof Error ? error.message : '登录异常'
      });
    }
  };

  const login = async () => {
    await handleAutoLogin();
  };

  const logout = () => {
    dispatch({ type: 'LOGOUT' });
    DeviceStorage.clearDeviceId();
    clearUserState();
  };

  const upgrade = async (phone: string, code: string, newUsername?: string): Promise<boolean> => {
    try {
      if (!state.user) {
        return false;
      }

      const response = await authAPI.upgrade({
        phone,
        code,
        new_username: newUsername
      });

      if (response.success && response.user_id) {
        dispatch({
          type: 'UPGRADE_SUCCESS',
          payload: {
            username: response.username || newUsername || state.user.username,
            status: response.status || 1
          }
        });

        // 更新本地存储
        saveUserState({
          ...state.user,
          username: response.username || newUsername || state.user.username,
          status: response.status || 1
        });

        return true;
      }
      return false;
    } catch {
      return false;
    }
  };

  const updateUsername = async (newUsername: string): Promise<boolean> => {
    try {
      const response = await authAPI.updateUsername({ new_username: newUsername });

      if (response.success && response.username) {
        dispatch({ type: 'UPDATE_USERNAME', payload: response.username });

        if (state.user) {
          saveUserState({ ...state.user, username: response.username });
        }

        return true;
      }
      return false;
    } catch {
      return false;
    }
  };

  return (
    <AuthContext.Provider
      value={{
        ...state,
        login,
        logout,
        upgrade,
        updateUsername
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import React, { createContext, useContext, useReducer, ReactNode } from 'react';
import type { ChatMessage } from '@/types';

interface ChatState {
  messages: ChatMessage[];
  isLoading: boolean;
  error: string | null;
  isTyping: boolean;
  streamingMessage: ChatMessage | null;
}

type ChatAction =
  | { type: 'SET_MESSAGES'; payload: ChatMessage[] }
  | { type: 'ADD_MESSAGE'; payload: ChatMessage }
  | { type: 'SET_LOADING'; payload: boolean }
  | { type: 'SET_ERROR'; payload: string | null }
  | { type: 'SET_TYPING'; payload: boolean }
  | { type: 'SET_LAST_ASSISTANT_MESSAGE'; payload: ChatMessage }
  | { type: 'CLEAR_STREAMING'; payload: undefined }
  | { type: 'CLEAR'; payload: undefined };

const initialState: ChatState = {
  messages: [],
  isLoading: false,
  error: null,
  isTyping: false,
  streamingMessage: null,
};

function chatReducer(state: ChatState, action: ChatAction): ChatState {
  switch (action.type) {
    case 'SET_MESSAGES':
      return { ...state, messages: action.payload };
    case 'ADD_MESSAGE':
      return { ...state, messages: [...state.messages, action.payload] };
    case 'SET_LOADING':
      return { ...state, isLoading: action.payload };
    case 'SET_ERROR':
      return { ...state, error: action.payload };
    case 'SET_TYPING':
      return { ...state, isTyping: action.payload };
    case 'SET_LAST_ASSISTANT_MESSAGE':
      return { ...state, streamingMessage: action.payload };
    case 'CLEAR_STREAMING':
      return { ...state, streamingMessage: null };
    case 'CLEAR':
      return initialState;
    default:
      return state;
  }
}

interface ChatContextType extends ChatState {
  dispatch: React.Dispatch<ChatAction>;
}

const ChatContext = createContext<ChatContextType | undefined>(undefined);

export function ChatProvider({ children }: { children: ReactNode }) {
  const [state, dispatch] = useReducer(chatReducer, initialState);

  return (
    <ChatContext.Provider value={{ ...state, dispatch }}>
      {children}
    </ChatContext.Provider>
  );
}

export function useChat() {
  const context = useContext(ChatContext);
  if (!context) {
    throw new Error('useChat must be used within a ChatProvider');
  }
  return context;
}

import React, { createContext, useContext, useReducer, ReactNode } from 'react';
import type { Paper, Question } from '@/types';

interface PaperState {
  currentPaper: Paper | null;
  questions: Question[];
  isLoading: boolean;
  error: string | null;
  isOcrDone: boolean;
  isAnswerGenerated: boolean;
  paperValidation: 'pending' | 'valid' | 'invalid';
  uploadedFile: File | null;
  previewImageUrl: string | null;
}

type PaperAction =
  | { type: 'SET_PAPER'; payload: Paper }
  | { type: 'SET_QUESTIONS'; payload: Question[] }
  | { type: 'UPDATE_QUESTION'; payload: Question }
  | { type: 'DELETE_QUESTION'; payload: string }
  | { type: 'SET_LOADING'; payload: boolean }
  | { type: 'SET_ERROR'; payload: string | null }
  | { type: 'SET_OCR_DONE'; payload: boolean }
  | { type: 'SET_ANSWER_GENERATED'; payload: boolean }
  | { type: 'SET_PAPER_VALIDATION'; payload: 'pending' | 'valid' | 'invalid' }
  | { type: 'SET_UPLOADED_FILE'; payload: File | null }
  | { type: 'SET_PREVIEW_IMAGE'; payload: string | null }
  | { type: 'UPDATE_QUESTION_ANSWER'; payload: { questionId: string; answer: string } }
  | { type: 'CLEAR'; payload: undefined };

const initialState: PaperState = {
  currentPaper: null,
  questions: [],
  isLoading: false,
  error: null,
  isOcrDone: false,
  isAnswerGenerated: false,
  paperValidation: 'pending',
  uploadedFile: null,
  previewImageUrl: null,
};

function paperReducer(state: PaperState, action: PaperAction): PaperState {
  switch (action.type) {
    case 'SET_PAPER':
      return { ...state, currentPaper: action.payload };
    case 'SET_QUESTIONS':
      return { ...state, questions: action.payload };
    case 'UPDATE_QUESTION':
      return {
        ...state,
        questions: state.questions.map((q) =>
          q.id === action.payload.id ? action.payload : q
        ),
      };
    case 'DELETE_QUESTION':
      return {
        ...state,
        questions: state.questions.filter((q) => q.id !== action.payload),
      };
    case 'SET_LOADING':
      return { ...state, isLoading: action.payload };
    case 'SET_ERROR':
      return { ...state, error: action.payload };
    case 'SET_OCR_DONE':
      return { ...state, isOcrDone: action.payload };
    case 'SET_ANSWER_GENERATED':
      return { ...state, isAnswerGenerated: action.payload };
    case 'SET_PAPER_VALIDATION':
      return { ...state, paperValidation: action.payload };
    case 'SET_UPLOADED_FILE':
      return { ...state, uploadedFile: action.payload };
    case 'SET_PREVIEW_IMAGE':
      return { ...state, previewImageUrl: action.payload };
    case 'UPDATE_QUESTION_ANSWER':
      return {
        ...state,
        questions: state.questions.map((q) =>
          q.id === action.payload.questionId
            ? { ...q, user_answer: action.payload.answer }
            : q
        ),
      };
    case 'CLEAR':
      return initialState;
    default:
      return state;
  }
}

interface PaperContextType extends PaperState {
  dispatch: React.Dispatch<PaperAction>;
}

const PaperContext = createContext<PaperContextType | undefined>(undefined);

export function PaperProvider({ children }: { children: ReactNode }) {
  const [state, dispatch] = useReducer(paperReducer, initialState);

  return (
    <PaperContext.Provider value={{ ...state, dispatch }}>
      {children}
    </PaperContext.Provider>
  );
}

export function usePaper() {
  const context = useContext(PaperContext);
  if (!context) {
    throw new Error('usePaper must be used within a PaperProvider');
  }
  return context;
}

export interface Paper {
  id: string;
  user_id: string;
  original_image_url: string;
  width: number;
  height: number;
  status: 'pending' | 'ocr_done' | 'answered' | 'exported';
  created_at: string;
  updated_at: string;
  is_valid_paper?: boolean;
  paper_type?: 'exam' | 'question' | 'other';
}

export interface Question {
  id: string;
  paper_id: string;
  content: string;
  ai_answer: string;
  user_answer: string;
  x: number;
  y: number;
  width: number;
  height: number;
  answer_x: number;
  answer_y: number;
  answer_width: number;
  answer_height: number;
  font_color: string;
  font_size: number;
  order: number;
  number: number;
  detected_number: string | null;
}

export interface Position {
  x: number;
  y: number;
  width: number;
  height: number;
}

export interface ApiResponse<T> {
  success: boolean;
  data: T;
  message?: string;
  error_code?: string;
}

export interface UploadResult {
  paper_id: string;
  image_url: string;
  width: number;
  height: number;
  is_pdf: boolean;
  page_count: number;
}

export interface OcrResult {
  paper_id: string;
  is_valid_paper: boolean;
  paper_type: 'exam' | 'question' | 'other';
  questions: Question[];
}

export interface ChatMessage {
  id: string;
  content: string;
  role: 'user' | 'assistant';
  paper_id?: string;
  created_at: string;
}

export interface ChatResponse {
  message_id: string;
  content: string;
  role: 'assistant';
  created_at: string;
}

export interface User {
  id: string;
  username: string;
  phone?: string;
  status: number;
  access_token: string;
  expired_at: string;
}

export interface HistoryItem extends Paper {
  preview_text: string;
  questions?: Question[];
}

