    <div className={`flex items-center gap-2 px-4 py-2 rounded-md mb-4 ${isWarning ? 'bg-orange-50 text-orange-600' : 'bg-cyan-50 text-cyan-700'}`}>
      <span className="flex-shrink-0">{getValidationIcon()}</span>
